import{_ as a,o as d,c as n,ah as i}from"./chunks/framework.NjRSjnv-.js";const b=JSON.parse('{"title":"Embedding","description":"","frontmatter":{"title":"Embedding","order":13},"headers":[],"relativePath":"ai/app/rag/embedding.md","filePath":"ai/app/rag/embedding.md"}'),r={name:"ai/app/rag/embedding.md"};function t(o,e,g,m,p,l){return d(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="embedding-模型" tabindex="-1">Embedding 模型 <a class="header-anchor" href="#embedding-模型" aria-label="Permalink to “Embedding 模型”">​</a></h1><p>Embedding 模型是将文本映射到高维向量空间的编码器，是 RAG、语义搜索、推荐系统等应用的基石。它的质量直接决定了检索的准确性——如果 Embedding 不能准确捕捉语义相似性，后续的重排序和生成再精巧也无济于事。理解 Embedding 模型的原理和选型，是构建高质量 RAG 系统的第一步。</p><h2 id="模型架构" tabindex="-1">模型架构 <a class="header-anchor" href="#模型架构" aria-label="Permalink to “模型架构”">​</a></h2><p>当代 Embedding 模型主要基于 Transformer 编码器架构，以 BERT 为代表。BERT 通过双向注意力机制理解上下文，将变长文本编码为固定维度的稠密向量。对于整句或段落的 Embedding，通常取 BERT 最后一层所有 token 向量的平均值（Mean Pooling）或 CLS token 的向量。</p><p>与生成式模型（GPT 系列）不同，BERT 类编码器在训练时能看到完整的输入序列，因此更适合理解语义相似性。但纯粹使用 CLS token 或平均池化的 BERT 在语义匹配任务上表现一般，因为预训练的 MLM（Masked Language Modeling）目标只关注 token 级别的预测，不直接优化句子级别的语义表示。</p><p>对比学习（Contrastive Learning）的引入是 Embedding 模型的关键突破。其核心思想是：语义相似的文本对（如问答对、同义句、同一文档的不同片段）在向量空间中距离更近，不相似的文本对距离更远。训练时，模型同时编码一对文本，用余弦相似度衡量距离，通过 InfoNCE 损失函数拉近正样本、推远负样本。这种训练方式直接优化了向量空间的语义结构，使得&quot;查询 - 文档&quot;的匹配效果远优于普通 BERT。</p><p>SimCSE 是早期的对比学习方法，将同一句话输入两次（第二次做 dropout 作为数据增强），作为正样本对训练。后来的模型普遍采用有监督的对比学习：Instructor 用任务指令（如&quot;表示这段文本用于检索&quot;）引导模型生成不同场景下的 Embedding；E5 系列通过大量弱监督数据（问答对、标题-正文对）训练，覆盖广泛的语义匹配场景；BGE 系列在此基础上增加了检索场景的负样本挖掘（Hard Negatives Mining），进一步提升了区分能力。</p><h2 id="模型选型" tabindex="-1">模型选型 <a class="header-anchor" href="#模型选型" aria-label="Permalink to “模型选型”">​</a></h2><p>选择 Embedding 模型需要考虑语言支持、向量维度、推理性能、部署成本和精度。</p><p>OpenAI 的 <code>text-embedding-3-small</code>（1536 维）和 <code>text-embedding-3-large</code>（3072 维）是闭源方案的代表，质量稳定但需要 API 调用，数据不能出境的场景不适用。<code>text-embedding-3</code> 支持维度裁剪（Matryoshka Representation Learning），可以在不重新训练的情况下将 3072 维裁剪到任意更小的维度，方便在精度和存储之间权衡。</p><p>开源模型中，BGE-M3（BAAI 发布）是目前综合表现最强的多语言模型，支持中英日韩等语言，支持稠密向量、稀疏向量（BM25 风格）和多向量（ColBERT 风格）三种检索方式，适合混合检索场景。E5-Mistral-7B-instruct 是基于 Mistral 7B 的大规模模型，精度极高但推理成本大。GTE-Qwen2 系列基于 Qwen2 架构，在中文场景表现优异。这些模型的向量维度通常在 768-1024 之间。</p><p>推理性能方面，模型大小直接影响延迟和吞吐。768 维的模型（如 BGE-base, GTE-base）适合高并发场景，单次编码延迟在毫秒级。1024 维及以上的模型（如 BGE-large, E5-large）精度更高但延迟翻倍。对于部署在 CPU 或边缘设备的场景，可以用 ONNX Runtime 或 TensorRT 加速推理，或者使用量化后的模型（INT8 量化几乎不损失精度，推理速度提升 2-3 倍）。</p><h2 id="评估-embedding" tabindex="-1">评估 Embedding <a class="header-anchor" href="#评估-embedding" aria-label="Permalink to “评估 Embedding”">​</a></h2><p>评估 Embedding 模型质量的标准方法是 MTEB（Massive Text Embedding Benchmark），它涵盖分类、聚类、检索、语义相似度、文本匹配等多个任务类型，用多个数据集的平均分排名。MTEB 排行榜（huggingface.co/spaces/mteb/leaderboard）是选型的首选参考。</p><p>但 MTEB 的排名不能完全替代实际业务评估。MTEB 的数据集以英文为主，中文检索任务的表现可能差异较大。更重要的是，MTEB 评估的是通用场景，特定领域（医疗、法律、金融）的术语和语义关系可能需要领域微调才能达到最佳效果。工程实践中，建议用 MTEB 缩短候选范围，再用自己的标注数据集做最终评估。</p><p>自建评估数据集的方法：准备 100-500 个 (query, 正例文档, 负例文档) 三元组，用 Embedding 模型编码后计算 query 与正例/负例的余弦相似度，统计命中率（Recall@K）和区分度（正例相似度 &gt; 负例相似度的比例）。Recall@1 超过 80%、Recall@5 超过 95% 通常说明 Embedding 质量足够。</p><h2 id="微调策略" tabindex="-1">微调策略 <a class="header-anchor" href="#微调策略" aria-label="Permalink to “微调策略”">​</a></h2><p>通用 Embedding 模型在特定领域上可能不够精准。微调可以让模型学习领域内的术语、缩写和语义关系，显著提升检索精度。微调数据通常需要数千到数万条 (query, 正例文档) 对，不需要负例（对比学习框架中同 batch 内的其他样本自动作为负例）。</p><p>微调方式取决于数据和场景。全参数微调在数据充足（&gt;10 万条）时效果最好，但计算成本高。LoRA 微调冻结基础模型，只训练低秩适配器，数据需求低（&gt;1000 条），是性价比最高的选择。对比学习微调（如 BGE 的训练流程）需要构建正负样本对，负样本的质量至关重要——随机负样本太简单，需要用 BM25 或已有 Embedding 模型筛选 Hard Negatives（与 query 语义相关但不是正确答案的文档），这样才能训练模型区分细微的语义差异。</p><p>微调后需要重新评估：在测试集上对比微调前后的 Recall@K，同时检查是否出现灾难性遗忘（通用能力下降）。如果数据量小，建议用 LoRA 微调并配合 L2 正则化，避免过拟合。</p>',20)])])}const s=a(r,[["render",t]]);export{b as __pageData,s as default};
